// Monitor serial ports and extract data from string
public void serialEvent(Serial port)

{

  newData = false;

  //println("into serial event");

  try {

    String incoming = port.readStringUntil('\n');

    if (incoming != null)
    {

      incoming = trim(incoming);

      // break up the decimal and new line reading
      int[] vals = PApplet.parseInt(splitTokens(incoming, ","));

      // we assign to variables
      incoming_leftJoystick_xAxis = vals[2];
      incoming_leftJoystick_yAxis = vals[3];
      incoming_rightJoystick_xAxis = vals[0];
      incoming_rightJoystick_yAxis = vals[1];

      newData = true;
    }
  }
  catch (Exception e) {

    println("Initialization exception");
  }
}

