public void drawFrame() {
  noFill();
  stroke(0);
  rectMode(CORNER);

  rectMode(CORNER);
  rect(0, 0, width, height);

  pushMatrix();
  translate(width-50, height-150);
  rotate(radians(90));
  drawCorner();
  popMatrix();

  pushMatrix();
  translate(width-150, 50);
  rotate(radians(0));
  drawCorner();
  popMatrix();

  pushMatrix();
  translate(50, 150);
  rotate(radians(-90));
  drawCorner();
  popMatrix();

  pushMatrix();
  translate(150, height-50);
  rotate(radians(-180));
  drawCorner();
  popMatrix();
}

//--------------------------------------------------------------

public void drawCorner() {
  if (screengrab) {
    fill(360);
    noStroke();
  } else {
    fill(0);
    stroke(0);
  }
  pushMatrix();
  translate(-150, -150);
  beginShape();
  vertex(100, 100);
  bezierVertex(300, 100, 300, 250, 300, 300);
  vertex(300, 300);
  vertex(300, 100);
  vertex(100, 100);
  endShape();
  popMatrix();
}

