  //--------------------------------------------------------------

  public void updateColorOnRotation(float t) {

    int newAngle = PApplet.parseInt(degrees(t));

    colorWheelAngle = newAngle;

    // make sure angle is between 0-360
    if (newAngle < 0) {
      colorWheelAngle += 360;
    }

    theta = t;

    centerSphere.applyColorWheel(colorWheelAngle);
  }

