class VehicleRipple { 

  float radius;
  
  float x, y;
  float speed;
  int colorTrail;
  
  int count;
  
  float opacity;
  int opacityCount;

  VehicleRipple(PVector pos, float rippleSpeed, int ct, float _opacityStart) {

    x = pos.x;
    y = pos.y;
    
    opacity = _opacityStart;
    
    speed = rippleSpeed;
    
    radius = 105;
    
    colorTrail = ct;
    
    opacityCount = 0;
    count = 0;
    
    
  }

//--------------------------------------------------------------


  public void update(int rippleNum) {
    
    int opacityPace;
    
    if(rippleNum < 2){
      opacityPace = 2;
    } else {
      opacityPace = rippleNum;
    }
    
    opacityCount++;
    
    count = opacityCount % opacityPace;
    
    if(count == 0){
      
      opacity -= rippleNum/3;
    }

    radius += speed;
   
    if (opacity<=0) {
      opacity=0;
      radius=0;
    }
  }

//--------------------------------------------------------------


  public void display() {

    fill(colorTrail, opacity);
    noStroke();
    circle (x, y, radius);
  }
}
class VehicleSphere {

  int cB, mB, gI;
  Body body;

  float w, h;
  Vec2 posVecPixels;
  float bodyRadius; 
  
  int red = color(255, 0, 0);
  int green = color(0, 255, 0);
  int blue = color(0, 0, 255);
  int col;

  boolean wasTouched;
  
  VehicleSphere(float _x, float _y, float _r, String type, int categoryBits, int maskBits) {

    bodyRadius = _r;
    cB = categoryBits;
    mB = maskBits;
  
    posVecPixels = new Vec2(_x, _y);  
    w = _r;
    h = _r;

    wasTouched = false;
  
    makeBody(type);

    col = color(175, 126);
  }

  public void makeBody(String type) {
    // Make each individual body
    BodyDef bd = new BodyDef();
    if (type == "DYNAMIC") {
      bd.type = BodyType.DYNAMIC;
    } else if (type == "STATIC") {
      bd.type = BodyType.STATIC;
    }

    bd.fixedRotation = true; // no rotation!
    bd.position.set(box2d.coordPixelsToWorld(posVecPixels.x, posVecPixels.y));

    /*
    bd.linearDamping = 1f;
     bd.angularDamping = 0.3f;
     */
    bd.linearDamping = 1.0f;
    bd.angularDamping = 0.3f;

    body = box2d.createBody(bd);

    CircleShape cs = new CircleShape();
    cs.m_radius = box2d.scalarPixelsToWorld(bodyRadius);
    Vec2 offset = new Vec2(0, 0);
    offset = box2d.vectorPixelsToWorld(offset);
    cs.m_p.set(offset.x, offset.y);

    // Define a fixture
    FixtureDef fd = new FixtureDef();
    fd.shape = cs;
    
    
    // Parameters that affect physics
    fd.density = 1;
    fd.friction = 0.1f;
    fd.restitution = 0.1f;
    

    // for collision avoidance
    fd.filter.categoryBits = cB;
    fd.filter.maskBits = mB;

    // Finalize the body
    body.createFixture(fd);

    body.setUserData(this);
    
    body.setLinearDamping(0.5f);

  }

  // This function removes the particle from the box2d world
  public void killBody() {
    box2d.destroyBody(body);
  }


  public void display() {
    // Get its angle of rotation
    float a = body.getAngle();
    Vec2 pos = box2d.getBodyPixelCoord(body);
    pushMatrix();
    translate(pos.x, pos.y);
    rotate(a);
    fill(col);
     circle(0, 0, bodyRadius);
    popMatrix();
  }

  public float velFriction(float origin, float dest, float coeff) {
    return (dest-origin)/coeff;
  }

  public void applyLinearVelocity(Vec2 vel) {
    body.setLinearVelocity(vel);
  }

  public void applyForce(Vec2 v) {
    body.applyForce(v, body.getWorldCenter());
  }

  // Change color when hit
  public void change() {
    col = color(0, 100, 100);
  }
}
class VehicleTrail {

  ArrayList<VehicleRipple> ripples;

  PVector ripplePos;
  PVector previousRipplePos;
  int rippleFrameCount;

  int rippleCount;
  int maxRipples;

  VehicleTrail(float x, float y) {

    ripples = new ArrayList<VehicleRipple>();

    ripplePos = new PVector(x, y);
    previousRipplePos = new PVector(x, y);
    rippleFrameCount = 0;
    
    //maxRipples = int(random(13, 50)); // FOR TESTING
    maxRipples = PApplet.parseInt(random(100, 150));

    rippleCount = 0;
  }
  
  //--------------------------------------------------------------

  public void update() {

    updateRipples();

    removeRipples();
    
  }
  
  //--------------------------------------------------------------

  public void display() {

    for (VehicleRipple r : ripples) {
      if (r != null) {

        r.display();
      }
    }
  }
  
  //--------------------------------------------------------------

  public void removeRipples(){
    
    for (int i= 0; i < ripples.size(); i++) {

      VehicleRipple r = ripples.get(i);

      if (r.opacity <=0) {
        ripples.remove(i);
      }
    }
  }
  
  //--------------------------------------------------------------
  
  public void updateRipples(){
    
    for (VehicleRipple r : ripples) {
      if (r != null) {
        r.update(ripples.size()-1);
      }
    }
  }
  
   //--------------------------------------------------------------
  
  public void addRipples(float x, float y, int colorTrail, float opacityStart){
    
    if (opacityStart > 0) {
      int count;

      previousRipplePos.set(ripplePos.x, ripplePos.y);
      ripplePos.set(x, y);

      float dist = dist(ripplePos.x, ripplePos.y, previousRipplePos.x, previousRipplePos.y);

      rippleFrameCount++;

      count = rippleFrameCount % 30;

      if (count == 0) {

        float rippleSpeed = map(dist, 5, 20, 0.2f, 2);
        ripples.add(new VehicleRipple(ripplePos, rippleSpeed, colorTrail, opacityStart));
        rippleCount++;
      }
    }
    
  }
  
}
interface VehicleZoneState {

  void update();

  public boolean getReadyToSetState();
  public void setReadyToSetState(boolean rtss);
}

class VehicleZone {

  VehicleZoneState state;

  VehicleZoneState holdState;
  VehicleZoneState emptyState;
  VehicleZoneState fullState;
  VehicleZoneState inhaleState;
  VehicleZoneState exhaleState;
  VehicleZoneState inMotionNoZoneState;
  VehicleZoneState collisionState;

  Vehicle vehicle;

  float radius;
  float radiusMax, radiusMin;
  float distanceRadius;
  float originalRadiusMax;
  float tempDistanceRadius;

  boolean isBreathing;
  boolean switchFromExhaleToInhale;

  //--------------------------------------------------------------

  VehicleZone(Vehicle v) {

    vehicle = v;
    
    //radiusMax = vehicle.unitHalfSize;
    radiusMax = unit_w;
    //radiusMax = bgTrailBox.rectSize * 0.5;
    //println("radiusMax ", radiusMax);
    radiusMin = vehicle.blobRadius+5;
    distanceRadius = radiusMax;
    originalRadiusMax = radiusMax;
    
    radius = radiusMin;

    holdState = new HoldZoneState();
    emptyState = new EmptyZoneState(vehicle);
    fullState = new FullZoneState(vehicle);
    exhaleState = new ExhaleZoneState();
    inhaleState = new InhaleZoneState(vehicle);
    inMotionNoZoneState = new InMotionNoZoneState();
    collisionState = new CollisionState(vehicle);



    switchFromExhaleToInhale = false;
  }

  //--------------------------------------------------------------

  public void setState(VehicleZoneState state) {
    this.state = state;
  }

  //--------------------------------------------------------------

  public VehicleZoneState getState() {
    return state;
  }

  //--------------------------------------------------------------

  public void update() {

    if (getState() != emptyState) {
      vehicle.readyToUpdateDistanceZone = true;
    }

    if (getState() != collisionState) { // test
      setZoneState();
    }

    state.update();

    resetStates();
  }

  public void resetStates() {

    if (getState() == exhaleState) {
      emptyState.setReadyToSetState(true);
    } else if (getState() == inhaleState) {
      fullState.setReadyToSetState(true);
      //collisionState.setReadyToSetState(true);//test
    } else if (getState() == fullState) {
      collisionState.setReadyToSetState(true);
    }
  }

  //--------------------------------------------------------------

  public void display() {

    ellipseMode(RADIUS);

    pushMatrix();

    translate(vehicle.posVecPixels.x, vehicle.posVecPixels.y);

    if (showDistance) {
      // outer circle for checking distance

      strokeWeight(3);
      stroke(vehicle.darkGrey);
      fill(vehicle.darkGrey);
      circle(0, 0, distanceRadius);
    }

    // repel / attract zone (breathing)

    strokeWeight(1);
    stroke(vehicle.colorBreathing);

    fill(vehicle.colorBreathing); // TEST
    circle(0, 0, radius);

    popMatrix();
  }


  //--------------------------------------------------------------
  public void setZoneState() {
     
    radius = map(vehicle.breath.radius, vehicle.breath.radiusMin, vehicle.breath.radiusMax, radiusMin, distanceRadius);

    // breathing radius

    isBreathing = true;

    switch(vehicle.breath.movement) {

    case "empty":
      setState(emptyState);
      break;
    case "breathing":

      if (vehicle.breath.direction == "inhale") {

        setState(inhaleState);

        switchFromExhaleToInhale = true;
      } else if (vehicle.breath.direction == "exhale") {

        setState(exhaleState);

        if (vehicle.playerInDistanceZone || vehicle.otherVehicleInDistanceZone) {

          if (switchFromExhaleToInhale) {

            vehicle.breath.aVelocity *= -1;
            switchFromExhaleToInhale = false;
          }
        }
      }

      break;

    case "full":
      setState(fullState);

      if (vehicle.playerInBreathingZone || vehicle.otherVehicleInBreathingZone) {

        isBreathing = false;
      } else { // no vehicle in area

        isBreathing = true;
      }
      break;
    default:
      break;
    }
  }

  //--------------------------------------------------------------

  public void resetRadius() { // called in Bg_Unit when vehicles wrap

    vehicle.zoneAgainstZones = true;
    distanceRadius = originalRadiusMax;
    radiusMax = originalRadiusMax;
  }


  //--------------------------------------------------------------
} // VehicleZone class

